{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires an optimization strategy for spatial sampling and a probabilistic reconstruction of shapes based on noisy feedback. I am splitting this into a search strategy subproblem and a shape reconstruction subproblem.",
  "helpers": [
    {
      "label": "sampling_optimizer",
      "instructions": "Develop a greedy or information-theoretic heuristic to select the next set of drilling coordinates. The heuristic must prioritize cells that maximize the expected reduction in uncertainty regarding the presence of a polyomino, accounting for the cost of drilling versus the potential information gain from noisy aggregate queries. Define the state transition rule for updating the probability map of oil presence after each query result is received."
    },
    {
      "label": "shape_reconstructor",
      "instructions": "Implement a probabilistic inference algorithm, such as a Bayesian update or a Markov Random Field, to map the noisy aggregate query results back to specific cell coordinates. Given a set of known polyomino templates and a sequence of noisy observations, calculate the posterior probability for each cell being part of an oil field. The algorithm must handle the noise model to distinguish between true oil presence and query error, outputting a set of coordinates that maximizes the likelihood of the observed data."
    }
  ],
  "synthesis_brief": "Combine the sampling optimizer's sequence of coordinates and query results with the shape reconstructor's posterior probability map to identify the most likely oil-containing cells, then format the final coordinates as the answer."
}
```

